 47	func quotaFromHarnessInfo(info agentlib.HarnessInfo) *ProviderQuota {
 48		if sig, ok := LookupHarnessRateLimit(info.Name); ok {
 49			if q := QuotaFromRateLimitSignal(sig); q != nil {
 50				return q
 51			}
 52		}
