 62	// remaining stay unknown unless a harness-specific rate-limit-header path
 63	// populates them via QuotaFromRateLimitSignal.
 64	func quotaFromState(state *agentlib.QuotaState) *ProviderQuota {
 65		if state == nil || len(state.Windows) == 0 {
 66			return nil
 67		}
 68		var windowSeconds int
 69		var resetAt string
 70		for _, w := range state.Windows {
 71			if strings.EqualFold(w.LimitID, "extra") {
 72				continue
 73			}
 74			if windowSeconds == 0 && w.WindowMinutes > 0 {
 75				windowSeconds = w.WindowMinutes * 60
 76			}
 77			if resetAt == "" {
 78				if w.ResetsAt != "" {
 79					resetAt = w.ResetsAt
 80				} else if w.ResetsAtUnix > 0 {
 81					resetAt = time.Unix(w.ResetsAtUnix, 0).UTC().Format(time.RFC3339)
 82				}
 83			}
 84			if windowSeconds > 0 && resetAt != "" {
 85				break
 86			}
 87		}
 88		if windowSeconds == 0 && resetAt == "" {
 89			return nil
 90		}
 91		q := &ProviderQuota{}
 92		if windowSeconds > 0 {
 93			v := windowSeconds
 94			q.CeilingWindowSeconds = &v
 95		}
 96		if resetAt != "" {
 97			v := resetAt
 98			q.ResetAt = &v
 99		}
100		return q
101	}

