251	// quotaFromProviderInfo derives a ProviderQuota from the upstream ProviderInfo.
252	// Returns nil when no token-level ceiling is published.
253	func quotaFromProviderInfo(p agentlib.ProviderInfo) *ProviderQuota {
254		if p.Quota == nil {
255			return nil
256		}
257		return quotaFromState(p.Quota)
258	}
259	
260	// quotaFromHarnessInfo derives a ProviderQuota from the upstream HarnessInfo.
261	// When a rate-limit signal has been captured for this harness (via
262	// RecordHarnessRateLimit — typically on the server's harness-dispatch path
263	// after parsing response headers with agent.ParseRateLimitHeaders), that
264	// signal takes precedence because it carries absolute token ceilings. The
265	// upstream HarnessInfo.Quota only exposes percent-used windows without an
266	// absolute ceiling. Returns nil when nothing usable is published.
267	func quotaFromHarnessInfo(info agentlib.HarnessInfo) *ProviderQuota {
268		if sig, ok := LookupHarnessRateLimit(info.Name); ok {
269			if q := QuotaFromRateLimitSignal(sig); q != nil {
270				return q
271			}
272		}
273		if info.Quota == nil {
274			return nil
275		}
276		return quotaFromState(info.Quota)
277	}
278	
279	// quotaFromState derives a ProviderQuota from an upstream QuotaState. The
280	// upstream QuotaWindow doesn't expose absolute token ceilings (only percent
281	// used), so we surface the window length and reset time only. Ceiling and
282	// remaining stay unknown unless a harness-specific rate-limit-header path
283	// populates them via QuotaFromRateLimitSignal.
284	func quotaFromState(state *agentlib.QuotaState) *ProviderQuota {
285		if state == nil || len(state.Windows) == 0 {
286			return nil
287		}
288		var windowSeconds int
289		var resetAt string
290		for _, w := range state.Windows {
291			if strings.EqualFold(w.LimitID, "extra") {
292				continue
293			}
294			if windowSeconds == 0 && w.WindowMinutes > 0 {
295				windowSeconds = w.WindowMinutes * 60
296			}
297			if resetAt == "" {
298				if w.ResetsAt != "" {
299					resetAt = w.ResetsAt
300				} else if w.ResetsAtUnix > 0 {
301					resetAt = time.Unix(w.ResetsAtUnix, 0).UTC().Format(time.RFC3339)
302				}
303			}
304			if windowSeconds > 0 && resetAt != "" {
305				break
306			}
307		}
308		if windowSeconds == 0 && resetAt == "" {
309			return nil
310		}
311		q := &ProviderQuota{}
312		if windowSeconds > 0 {
313			v := windowSeconds
314			q.CeilingWindowSeconds = &v
315		}
316		if resetAt != "" {
317			v := resetAt
318			q.ResetAt = &v
319		}
320		return q
321	}

